// Validate secret (dual pattern) + update NocoDB content row
const data = $input.first().json;
const body = data.body || data;

// Dual-secret validation: body.secret OR x-webhook-secret header
const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;
if (!expectedSecret) throw new Error('N8N_WEBHOOK_HMAC_SECRET not configured');
const receivedSecret = (data.headers || {})['x-webhook-secret'] || body.secret || '';
if (receivedSecret !== expectedSecret) throw new Error('Unauthorized: invalid webhook secret');

const content_id = body.content_id;
if (!content_id) throw new Error('Missing required field: content_id');

const fields = body.fields || {};
if (Object.keys(fields).length === 0) throw new Error('Missing required field: fields (nothing to update)');

// Stringify any nested objects before sending to NocoDB
const patchFields = {};
for (const [key, value] of Object.entries(fields)) {
  patchFields[key] = (typeof value === 'object' && value !== null) ? JSON.stringify(value) : value;
}

// Resolve NocoDB table IDs
const baseUrl = $env.NOCODB_BASE_URL;
const token = $env.NOCODB_API_TOKEN;
let baseId = $env.NOCODB_CF_BASE_ID || '';
let contentsId = $env.NOCODB_CONTENTS_TABLE_ID || '';

if (!baseId || !contentsId) {
  const basesResp = await $http.request({
    method: 'GET',
    url: `${baseUrl}/api/v2/meta/bases/`,
    headers: { 'xc-token': token }
  });
  const base = (basesResp.list || []).find(b => b.title === 'content-factory');
  if (!base) throw new Error('NocoDB base content-factory not found');
  baseId = base.id;

  const tablesResp = await $http.request({
    method: 'GET',
    url: `${baseUrl}/api/v2/meta/bases/${baseId}/tables`,
    headers: { 'xc-token': token }
  });
  const contentsTable = (tablesResp.list || []).find(t => t.title === 'contents');
  if (!contentsTable) throw new Error('NocoDB table contents not found');
  contentsId = contentsTable.id;
}

// PATCH content row
await $http.request({
  method: 'PATCH',
  url: `${baseUrl}/api/v2/meta/bases/${baseId}/tables/${contentsId}/records`,
  headers: {
    'xc-token': token,
    'Content-Type': 'application/json'
  },
  body: { Id: parseInt(content_id), ...patchFields }
});

return [{ json: { status: 'ok', content_id: String(content_id) } }];
